Here are the changes to fix the previous error and implement the new "Informes" (Reports) section with PDF generation based on the provided boletín format.

# Updated files:

## utils/permissions.ts

Added `VIEW_REPORTS` permission and assigned it to all roles.

```typescript
import { UserRole } from '../types';

export enum Action {
  // Super Admin Actions
  MANAGE_CAMPUSES = 'manage:campuses',
  MANAGE_ADMINS = 'manage:admins',
  VIEW_GLOBAL_SETTINGS = 'view:global_settings',

  // Campus Admin Actions
  MANAGE_STUDENTS = 'manage:students',
  MANAGE_TEACHERS = 'manage:teachers',
  MANAGE_EXAMS = 'manage:exams',
  MANAGE_LIBRARY = 'manage:library',
  MANAGE_TRANSPORT = 'manage:transport',
  VIEW_CAMPUS_SETTINGS = 'view:campus_settings',
  MANAGE_COMMUNICATIONS = 'manage:communications',

  // Teacher Actions
  VIEW_OWN_STUDENTS = 'view:my-students',
  MANAGE_GRADES = 'manage:grades',
  VIEW_SCHEDULE = 'view:schedule',
  VIEW_TEACHER_EXAMS = 'view:teacher_exams',
  MANAGE_TEACHER_EXAMS = 'manage:teacher_exams',

  // Student Actions
  VIEW_OWN_GRADES = 'view:own_grades',
  VIEW_OWN_SCHEDULE = 'view:own_schedule',
  VIEW_OWN_PROFILE = 'view:own_profile',

  // Parent Actions
  VIEW_CHILD_GRADES = 'view:child_grades',
  VIEW_CHILD_SCHEDULE = 'view:child_schedule',
  VIEW_CHILD_PROFILE = 'view:child_profile',

  // Common Actions
  VIEW_DASHBOARD = 'view:dashboard',
  VIEW_REPORTS = 'view:reports',
}

const rolePermissions: { [key in UserRole]: Action[] } = {
  [UserRole.SUPER_ADMIN]: [
    Action.VIEW_DASHBOARD,
    Action.MANAGE_CAMPUSES,
    Action.MANAGE_ADMINS,
    Action.VIEW_GLOBAL_SETTINGS,
    Action.MANAGE_COMMUNICATIONS,
    Action.MANAGE_STUDENTS,
    Action.VIEW_REPORTS,
  ],
  [UserRole.CAMPUS_ADMIN]: [
    Action.VIEW_DASHBOARD,
    Action.MANAGE_STUDENTS,
    Action.MANAGE_TEACHERS,
    Action.MANAGE_EXAMS,
    Action.VIEW_CAMPUS_SETTINGS,
    Action.MANAGE_COMMUNICATIONS,
    Action.VIEW_REPORTS,
  ],
  [UserRole.TEACHER]: [
    Action.VIEW_DASHBOARD,
    Action.VIEW_OWN_STUDENTS,
    Action.VIEW_TEACHER_EXAMS,
    Action.MANAGE_TEACHER_EXAMS,
    Action.MANAGE_GRADES,
    Action.VIEW_SCHEDULE,
    Action.VIEW_REPORTS,
  ],
  [UserRole.STUDENT]: [
    Action.VIEW_DASHBOARD,
    Action.VIEW_OWN_GRADES,
    Action.VIEW_OWN_SCHEDULE,
    Action.VIEW_OWN_PROFILE,
    Action.VIEW_REPORTS,
  ],
  [UserRole.PARENT]: [
    Action.VIEW_DASHBOARD,
    Action.VIEW_CHILD_GRADES,
    Action.VIEW_CHILD_SCHEDULE,
    Action.VIEW_CHILD_PROFILE,
    Action.VIEW_REPORTS,
  ],
};

export const hasPermission = (role: UserRole, action: Action): boolean => {
  return rolePermissions[role]?.includes(action) || false;
};
```

## components/layout/Sidebar.tsx

Added the "Informes" menu item.

```typescript
import React from 'react';
import { useAuth } from '../../context/AuthContext';
import { UserRole } from '../../types';
import { DashboardIcon, StudentsIcon, SettingsIcon, LogoutIcon, BuildingOfficeIcon, MegaphoneIcon, CalendarIcon, AcademicCapIcon, ShieldCheckIcon, IdentificationIcon, ExamsIcon, LibraryIcon, TransportIcon, DocumentTextIcon } from '../icons';
import { Action, hasPermission } from '../../utils/permissions';

interface SidebarProps {
  currentPage: string;
  setCurrentPage: (page: string) => void;
  isOpen: boolean;
}

const NavLink: React.FC<{ icon: React.ReactElement<{ className?: string }>; label: string; pageName: string; currentPage: string; setCurrentPage: (page: string) => void; }> = ({ icon, label, pageName, currentPage, setCurrentPage }) => {
  const isActive = currentPage === pageName;
  return (
    <li
      onClick={() => setCurrentPage(pageName)}
      className={`flex items-center px-4 py-3 cursor-pointer rounded-r-full mr-4 transition-all duration-200 ${
        isActive 
          ? 'bg-primary/10 text-primary font-bold border-l-4 border-primary dark:bg-primary/20 dark:text-sky-400' 
          : 'text-text-secondary hover:bg-gray-100 hover:text-primary border-l-4 border-transparent dark:text-slate-400 dark:hover:bg-slate-700/50 dark:hover:text-slate-200'
      }`}
    >
      {React.cloneElement(icon, { className: `w-5 h-5 mr-3 ${isActive ? 'text-primary dark:text-sky-400' : 'text-gray-400 dark:text-slate-500 group-hover:text-primary'}` })}
      <span className="text-sm">{label}</span>
    </li>
  );
};

const Sidebar: React.FC<SidebarProps> = ({ currentPage, setCurrentPage, isOpen }) => {
  const { user, logout } = useAuth();

  const getNavItems = () => {
    if (!user) return [];

    const allPossibleItems = [
      // Common
      { page: 'dashboard', permission: Action.VIEW_DASHBOARD, icon: <DashboardIcon />, label: 'Panel Principal' },

      // Super Admin & Campus Admin (ordered by importance)
      { page: 'admins', permission: Action.MANAGE_ADMINS, icon: <ShieldCheckIcon />, label: 'Administradores' },
      { page: 'campuses', permission: Action.MANAGE_CAMPUSES, icon: <BuildingOfficeIcon />, label: 'Gestión de Sedes' },
      { page: 'students', permission: Action.MANAGE_STUDENTS, icon: <AcademicCapIcon />, label: 'Grados y Estudiantes' },

      // Campus Admin Specific
      { page: 'teachers', permission: Action.MANAGE_TEACHERS, icon: <IdentificationIcon />, label: 'Profesores' },
      { page: 'exams', permission: Action.MANAGE_EXAMS, icon: <ExamsIcon />, label: 'Exámenes' },
      { page: 'communications', permission: Action.MANAGE_COMMUNICATIONS, icon: <MegaphoneIcon />, label: 'Comunicaciones' },
      { page: 'campus-settings', permission: Action.VIEW_CAMPUS_SETTINGS, icon: <SettingsIcon />, label: 'Configuración Sede' },

      // Teacher
      { page: 'my-students', permission: Action.VIEW_OWN_STUDENTS, icon: <StudentsIcon />, label: 'Mis Estudiantes' },
      { page: 'teacher-exams', permission: Action.VIEW_TEACHER_EXAMS, icon: <ExamsIcon />, label: 'Exámenes' },
      { page: 'grades', permission: Action.MANAGE_GRADES, icon: <ExamsIcon />, label: 'Calificaciones' },
      { page: 'schedule', permission: Action.VIEW_SCHEDULE, icon: <CalendarIcon />, label: 'Mi Horario' },

      // Reports (Informes)
      { page: 'reports', permission: Action.VIEW_REPORTS, icon: <DocumentTextIcon />, label: 'Informes' },

      // Student
      { page: 'student-grades', permission: Action.VIEW_OWN_GRADES, icon: <AcademicCapIcon />, label: 'Mis Calificaciones' },
      { page: 'student-schedule', permission: Action.VIEW_OWN_SCHEDULE, icon: <CalendarIcon />, label: 'Mi Horario' },
      { page: 'student-profile', permission: Action.VIEW_OWN_PROFILE, icon: <StudentsIcon />, label: 'Mi Perfil' },

      // Parent
      { page: 'parent-grades', permission: Action.VIEW_CHILD_GRADES, icon: <AcademicCapIcon />, label: 'Calificaciones (Hijo/a)' },
      { page: 'parent-schedule', permission: Action.VIEW_CHILD_SCHEDULE, icon: <CalendarIcon />, label: 'Horario (Hijo/a)' },
      { page: 'parent-profile', permission: Action.VIEW_CHILD_PROFILE, icon: <StudentsIcon />, label: 'Perfil (Hijo/a)' },

      // Placeholders
      { page: 'library', permission: Action.MANAGE_LIBRARY, icon: <LibraryIcon />, label: 'Biblioteca' },
      { page: 'transport', permission: Action.MANAGE_TRANSPORT, icon: <TransportIcon />, label: 'Transporte' },

      // Super Admin - moved to end
      { page: 'settings', permission: Action.VIEW_GLOBAL_SETTINGS, icon: <SettingsIcon />, label: 'Configuración Global' },
    ];

    return allPossibleItems.filter(item => hasPermission(user.role, item.permission));
  };

  const navItems = getNavItems();

  return (
    <aside className="bg-surface h-full flex flex-col overflow-hidden dark:bg-slate-800 dark:border-r dark:border-slate-700 pt-4">
        {/* Sidebar Content */}
        <nav className="flex-1 px-0 py-2 space-y-1 overflow-y-auto custom-scrollbar">
            <ul>
              {navItems.map(item => (
                <NavLink 
                  key={item.page}
                  icon={item.icon}
                  label={item.label}
                  pageName={item.page}
                  currentPage={currentPage}
                  setCurrentPage={setCurrentPage}
                />
              ))}
            </ul>
        </nav>
        <div className="p-4 border-t border-gray-200 dark:border-slate-700 bg-gray-50 dark:bg-slate-900/30">
          <li
            onClick={logout}
            className="flex items-center px-4 py-2.5 cursor-pointer rounded-lg text-text-secondary hover:bg-red-50 hover:text-red-600 transition-all duration-200 dark:text-slate-400 dark:hover:bg-red-900/20 dark:hover:text-red-400"
          >
            <LogoutIcon className="w-5 h-5 mr-3" />
            <span className="font-medium text-sm">Cerrar Sesión</span>
          </li>
        </div>
    </aside>
  );
};

export default Sidebar;
```

## components/layout/DashboardLayout.tsx

Registered the new Reports route.

```typescript
import React, { useState, useEffect } from 'react';
import Header from './Header';
import Sidebar from './Sidebar';
import DashboardPage from '../dashboard/DashboardPage';
import StudentManagementPage from '../students/StudentManagementPage';
import CampusManagementPage from '../campuses/CampusManagementPage';
import AdminManagementPage from '../admins/AdminManagementPage';
import TeacherManagementPage from '../teachers/TeacherManagementPage';
import MyStudentsPage from '../teachers/MyStudentsPage';
import GradesPage from '../teachers/GradesPage';
import CommunicationsPage from '../communications/CommunicationsPage';
import SchedulePage from '../teachers/SchedulePage';
import { useAuth } from '../../context/AuthContext';
import { Action, hasPermission } from '../../utils/permissions';
import LoginPage from '../auth/LoginPage';
import GlobalSettingsPage from '../settings/GlobalSettingsPage';
import ExamsManagementPage from '../exams/ExamsManagementPage';
import TeacherExamsPage from '../teachers/ExamsPage';
import StudentGradesPage from '../students/StudentGradesPage';
import StudentSchedulePage from '../students/StudentSchedulePage';
import StudentProfilePage from '../students/StudentProfilePage';
import ParentGradesPage from '../parents/ParentGradesPage';
import ParentSchedulePage from '../parents/ParentSchedulePage';
import ParentProfilePage from '../parents/ParentProfilePage';
import ReportsPage from '../reports/ReportsPage';
import Footer from './Footer';

const PlaceholderPage: React.FC<{title: string}> = ({title}) => (
    <div className="p-4 bg-surface rounded-lg shadow-md">
        <h1 className="text-2xl font-bold">{title}</h1>
        <p className="mt-2 text-text-secondary text-sm">Este módulo está en construcción. Vuelve pronto para ver las actualizaciones.</p>
    </div>
);

const AccessDeniedPage: React.FC = () => (
    <div className="p-4 bg-surface rounded-lg shadow-md text-center">
        <h1 className="text-2xl font-bold text-red-600">Acceso Denegado</h1>
        <p className="mt-2 text-text-secondary text-sm">No tiene los permisos necesarios para ver esta página.</p>
    </div>
);

const pagePermissions: { [key: string]: Action } = {
  dashboard: Action.VIEW_DASHBOARD,
  campuses: Action.MANAGE_CAMPUSES,
  admins: Action.MANAGE_ADMINS,
  settings: Action.VIEW_GLOBAL_SETTINGS,
  students: Action.MANAGE_STUDENTS,
  teachers: Action.MANAGE_TEACHERS,
  exams: Action.MANAGE_EXAMS,
  library: Action.MANAGE_LIBRARY,
  transport: Action.MANAGE_TRANSPORT,
  'campus-settings': Action.VIEW_CAMPUS_SETTINGS,
  communications: Action.MANAGE_COMMUNICATIONS,
  // Teacher
  'my-students': Action.VIEW_OWN_STUDENTS,
  'teacher-exams': Action.VIEW_TEACHER_EXAMS,
  grades: Action.MANAGE_GRADES,
  schedule: Action.VIEW_SCHEDULE,
  // Student
  'student-grades': Action.VIEW_OWN_GRADES,
  'student-schedule': Action.VIEW_OWN_SCHEDULE,
  'student-profile': Action.VIEW_OWN_PROFILE,
  // Parent
  'parent-grades': Action.VIEW_CHILD_GRADES,
  'parent-schedule': Action.VIEW_CHILD_SCHEDULE,
  'parent-profile': Action.VIEW_CHILD_PROFILE,
  // Reports
  'reports': Action.VIEW_REPORTS,
};


const DashboardLayout: React.FC = () => {
  const [currentPage, setCurrentPage] = useState('dashboard');
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const { user } = useAuth();

  const renderCurrentPage = () => {
    if (!user) return <LoginPage />; // Should not happen if layout is rendered, but for safety.

    const requiredPermission = pagePermissions[currentPage];
    if (requiredPermission && !hasPermission(user.role, requiredPermission)) {
        return <AccessDeniedPage />;
    }

    switch (currentPage) {
      case 'dashboard':
        return <DashboardPage />;
      case 'students':
        return <StudentManagementPage />;
      case 'teachers':
        return <TeacherManagementPage />;
      case 'exams':
        return <ExamsManagementPage />;
       case 'teacher-exams':
        return <TeacherExamsPage />;
      case 'campuses':
        return <CampusManagementPage />;
      case 'admins':
        return <AdminManagementPage />;
      case 'settings':
        return <GlobalSettingsPage />;
      case 'my-students':
        return <MyStudentsPage />;
      case 'grades':
        return <GradesPage />;
      case 'communications':
        return <CommunicationsPage />;
      case 'schedule':
        return <SchedulePage />;
      case 'campus-settings':
        return <GlobalSettingsPage />;
      case 'student-grades':
        return <StudentGradesPage />;
      case 'student-schedule':
        return <StudentSchedulePage />;
      case 'student-profile':
        return <StudentProfilePage />;
      case 'parent-grades':
        return <ParentGradesPage />;
      case 'parent-schedule':
        return <ParentSchedulePage />;
      case 'parent-profile':
        return <ParentProfilePage />;
      case 'reports':
        return <ReportsPage />;
      default:
        return <PlaceholderPage title={currentPage.replace(/-/g, ' ').replace(/\b\w/g, l => l.toUpperCase())} />;
    }
  };

  const toggleSidebar = () => {
    setSidebarOpen(!sidebarOpen);
  };

  // Close sidebar when changing page on mobile/desktop since it's a drawer now
  const handlePageChange = (page: string) => {
      setCurrentPage(page);
      setSidebarOpen(false);
  };

  return (
    <div className="flex h-screen bg-background dark:bg-slate-900 relative overflow-hidden">
      {/* Backdrop Overlay */}
      {sidebarOpen && (
          <div 
            className="fixed inset-0 bg-black/50 z-40 transition-opacity duration-300 backdrop-blur-sm" 
            onClick={toggleSidebar}
          ></div>
      )}

      {/* Sidebar Drawer */}
      <div className={`fixed inset-y-0 left-0 z-50 w-72 transform ${sidebarOpen ? 'translate-x-0' : '-translate-x-full'} transition-transform duration-300 ease-in-out shadow-2xl`}>
         <Sidebar currentPage={currentPage} setCurrentPage={handlePageChange} isOpen={true} />
      </div>

      <div className="flex-1 flex flex-col h-full w-full overflow-hidden">
        <Header toggleSidebar={toggleSidebar} />
        <main className="flex-1 overflow-x-hidden overflow-y-auto p-4 sm:p-6 scroll-smooth">
          <div className="w-full px-2 sm:px-4">
            {renderCurrentPage()}
          </div>
        </main>
        <Footer />
      </div>
    </div>
  );
};

export default DashboardLayout;
```

## components/reports/ReportsPage.tsx

New file that implements the PDF generation logic mimicking the attached image (Boletín).

```typescript
import React, { useState, useMemo, useEffect } from 'react';
import { useAuth } from '../../context/AuthContext';
import { useData } from '../../context/DataContext';
import { Student, UserRole, Grade } from '../../types';
import Card from '../ui/Card';
import { DocumentTextIcon, DownloadIcon } from '../icons';
import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";
import { conceptsCSV, getPeriodFromDate } from '../teachers/GradesPage';

const ReportsPage: React.FC = () => {
    const { user } = useAuth();
    const { students: allStudents, grades, attendanceRecords, teachers } = useData();
    const [searchQuery, setSearchQuery] = useState('');
    const [selectedStudent, setSelectedStudent] = useState<Student | null>(null);
    const [concepts, setConcepts] = useState<{ code: string; text: string }[]>([]);
    const [numberOfPeriods, setNumberOfPeriods] = useState(4);

    useEffect(() => {
        const parsed = conceptsCSV
            .split('\n').slice(1).filter(row => row.trim())
            .map(row => {
                const parts = row.split(';');
                const code = parts.pop()?.trim() || '';
                const text = parts.join(';').trim().replace(/^\uFEFF/, '');
                return { code, text };
            }).filter(c => c.code && c.text);
        setConcepts(parsed);

        // Load number of periods
        let settings = null;
        const globalSettingsRaw = localStorage.getItem('school_global_settings');
        if (globalSettingsRaw) {
            settings = JSON.parse(globalSettingsRaw);
        }
        if (user?.campusId) {
            const campusSettingsRaw = localStorage.getItem(`school_settings_${user.campusId}`);
            if (campusSettingsRaw) {
                settings = { ...settings, ...JSON.parse(campusSettingsRaw) };
            }
        }
        if (settings && settings.numberOfPeriods) {
            setNumberOfPeriods(settings.numberOfPeriods);
        }
    }, [user]);

    const accessibleStudents = useMemo(() => {
        if (!user) return [];
        if (user.role === UserRole.STUDENT) {
            return allStudents.filter(s => s.id === user.id);
        }
        if (user.role === UserRole.PARENT) {
            return allStudents.filter(s => s.id === (user as any).studentId); // Assuming Parent has studentId linkage
        }
        let filtered = allStudents;
        if (user.role === UserRole.CAMPUS_ADMIN) {
            filtered = filtered.filter(s => s.campusId === user.campusId);
        }
        // Teachers see all students in their campus for report purposes (simplified)
        if (user.role === UserRole.TEACHER) {
            filtered = filtered.filter(s => s.campusId === user.campusId);
        }

        return filtered.filter(s => 
            s.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
            s.documentNumber.includes(searchQuery)
        );
    }, [user, allStudents, searchQuery]);

    const getQualitativeScore = (score: number) => {
        if (score >= 4.6) return 'Superior';
        if (score >= 4.0) return 'Alto';
        if (score >= 3.0) return 'Básico';
        return 'Bajo';
    };

    const getConceptText = (code?: string) => {
        if (!code) return '';
        const concept = concepts.find(c => c.code === code);
        return concept ? concept.text : '';
    };

    const generatePDF = (student: Student) => {
        const doc = new jsPDF();

        // --- 1. Header Information ---
        let schoolName = 'INSTITUCIÓN EDUCATIVA';
        let schoolLogo = null;
        let rectorName = 'Rector';

        const globalSettingsRaw = localStorage.getItem('school_global_settings');
        if (globalSettingsRaw) {
            const s = JSON.parse(globalSettingsRaw);
            if (s.schoolName) schoolName = s.schoolName.toUpperCase();
            if (s.schoolLogo) schoolLogo = s.schoolLogo;
            if (s.rector) rectorName = s.rector;
        }

        // Logo
        if (schoolLogo) {
            try {
                doc.addImage(schoolLogo, 'PNG', 15, 10, 25, 25);
                doc.addImage(schoolLogo, 'PNG', 170, 10, 25, 25); // Right side logo as per image
            } catch (e) { console.error('Logo error', e); }
        }

        // Title
        doc.setFont('helvetica', 'bold');
        doc.setFontSize(14);
        doc.text(schoolName, 105, 20, { align: 'center' });

        doc.setFontSize(9);
        doc.setFont('helvetica', 'normal');
        doc.text('Aprobación de estudios res. 356 de julio 21 de 1997', 105, 25, { align: 'center' });
        doc.text('Resolución de fusión y asociación Nº 376 de abril 21 de 2003', 105, 29, { align: 'center' });
        doc.text('Código DANE 252560000340   NIT. 814000314-0', 105, 33, { align: 'center' });

        doc.setFontSize(12);
        doc.setFont('helvetica', 'bold');
        doc.text(`AÑO ESCOLAR ${new Date().getFullYear()}`, 105, 40, { align: 'center' });

        // --- 2. Student Info Table ---
        const studentInfoBody = [[
            student.id.substring(0,6) || '-', // Id (mock)
            student.documentNumber, // Código
            student.name.split(' ')[1] || '', // Apellido (Approx)
            student.name.split(' ')[0] || '', // Nombre (Approx)
            student.class + ' ' + student.section, // Curso
            student.campusName || 'Principal', // Sede
            'Diurna' // Jornada (Mock)
        ]];

        autoTable(doc, {
            startY: 45,
            head: [['Id', 'Código', 'Apellido', 'Nombre', 'Curso:', 'Sede:', 'Jornada:']],
            body: studentInfoBody,
            theme: 'plain',
            styles: {
                fontSize: 9,
                cellPadding: 1,
                lineColor: [0, 0, 0],
                lineWidth: 0.1,
            },
            headStyles: { fontStyle: 'bold', fillColor: [255, 255, 255], textColor: [0,0,0] }
        });

        // --- 3. Grades Data Prep ---
        const studentGrades = grades.filter(g => g.studentId === student.id);
        const subjects = Array.from(new Set(studentGrades.map(g => g.subject)));

        const tableBody: any[] = [];

        subjects.forEach(subject => {
            const subjectGrades = studentGrades.filter(g => g.subject === subject);

            // Calculate Period Grades
            const periodData: any = {}; // { 1: {grade: 4.5, faults: 2}, 2: ... }

            for(let p = 1; p <= numberOfPeriods; p++) {
                const pGrades = subjectGrades.filter(g => getPeriodFromDate(g.date, numberOfPeriods) === p);
                if (pGrades.length > 0) {
                    const totalScore = pGrades.reduce((acc, g) => acc + (g.score * g.percentage/100), 0);
                    const totalPerc = pGrades.reduce((acc, g) => acc + g.percentage, 0);
                    const final = totalPerc > 0 ? (totalScore / totalPerc) * 100 * (5/100) : 0;

                    const faults = attendanceRecords
                        .filter(r => r.studentId === student.id && r.period === p && r.status !== 'Presente')
                        .reduce((acc, r) => acc + (r.count || 1), 0);

                    periodData[p] = { grade: final, faults };
                } else {
                    periodData[p] = { grade: 0, faults: 0 };
                }
            }

            // Calculate Accumulated
            let accGradeSum = 0;
            let accGradeCount = 0;
            let accFaults = 0;
            Object.values(periodData).forEach((d: any) => {
                if (d.grade > 0) {
                    accGradeSum += d.grade;
                    accGradeCount++;
                }
                accFaults += d.faults;
            });
            const avgGrade = accGradeCount > 0 ? accGradeSum / accGradeCount : 0;
            const qualitative = getQualitativeScore(avgGrade);

            // Find Teacher
            const teacher = teachers.find(t => t.subject === subject && t.campusId === student.campusId); // Simplified matching
            const teacherName = teacher ? teacher.name : 'N/A';

            // Find Concept (Descriptor)
            // Use the last grade's concept code or default text
            const lastGrade = subjectGrades[subjectGrades.length - 1];
            const descriptor = getConceptText(lastGrade?.conceptCode) || "El estudiante demuestra las competencias básicas esperadas para el grado.";

            // Row 1: Data
            const rowData = [
                subject.toUpperCase(),
                periodData[1]?.grade ? periodData[1].grade.toFixed(1) : '',
                periodData[1]?.faults || 0,
                periodData[2]?.grade ? periodData[2].grade.toFixed(1) : '',
                periodData[2]?.faults || 0,
                periodData[3]?.grade ? periodData[3].grade.toFixed(1) : '',
                periodData[3]?.faults || 0,
                qualitative,
                accFaults,
                avgGrade.toFixed(3)
            ];
            tableBody.push(rowData);

            // Row 2: Teacher
            tableBody.push([{ content: `Profesor ${teacherName}`, colSpan: 10, styles: { fontStyle: 'italic', fontSize: 8, textColor: 50, cellPadding: {top:0, bottom: 0, left: 2} } }]);

            // Row 3: Descriptor
            tableBody.push([{ content: descriptor, colSpan: 10, styles: { fontSize: 8, cellPadding: {top:0, bottom: 2, left: 2} } }]);
        });

        // --- 4. Render Grades Table ---
        autoTable(doc, {
            startY: (doc as any).lastAutoTable.finalY + 2,
