            }
        });

        // --- 5. Observations & Footer ---
        let finalY = (doc as any).lastAutoTable.finalY + 5;

        // Check page break
        if (finalY > 250) {
            doc.addPage();
            finalY = 20;
        }

        autoTable(doc, {
