const dayOfWeekMap = ["Domingo", "Lunes", "Martes", "Miércoles", "Jueves", "Viernes", "Sábado"];

const ParentSchedulePage: React.FC = () => {
    const { user } = useAuth();
    const { students, schedules: allSchedules, teachers } = useData();
