        if (user.role === UserRole.PARENT) {
            return allStudents.filter(s => s.id === (user as any).studentId); 
        }

        if (user.role === UserRole.CAMPUS_ADMIN || user.role === UserRole.TEACHER) {
            filtered = filtered.filter(s => s.campusId === user.campusId);
        }

        if (filterClass) {
