import React, { useState, useEffect } from 'react';
import { useAuth } from '../../context/AuthContext';
import { Student, Grade, Exam, ClassSchedule, Teacher } from '../../types';
import StatCard from '../dashboard/StatCard';
import { AcademicCapIcon, ExamsIcon, ClipboardDocumentListIcon } from '../icons';
import Card from '../ui/Card';
import { useData } from '../../context/DataContext';

const StudentDashboard: React.FC = () => {
    const { user } = useAuth();
    const student = user as Student;

    // Use useData to access data sources (works for both local and Supabase)
    const { grades: allGrades, exams: allExams, schedules: allSchedules, teachers } = useData();

    const [grades, setGrades] = useState<Grade[]>([]);
    const [exams, setExams] = useState<Exam[]>([]);
    const [schedules, setSchedules] = useState<ClassSchedule[]>([]);

    useEffect(() => {
        if (!student) return;

        setGrades(allGrades.filter(g => g.studentId === student.id));
        setExams(allExams.filter(e => e.campusId === student.campusId));
        setSchedules(allSchedules.filter(s => s.class === student.class && s.section === student.section));
    }, [student, allGrades, allExams, allSchedules]);

    // --- Calculations for Stat Cards ---
    const calculateOverallAverage = () => {
        if (grades.length === 0) return "N/A";
        // Calculate weighted sum: sum(score * percentage_decimal)
        const totalScore = grades.reduce((acc, grade) => acc + (grade.score * (grade.percentage / 100)), 0);
        // Calculate total percentage accumulated so far
        const totalPercentage = grades.reduce((acc, grade) => acc + grade.percentage, 0);

        if (totalPercentage === 0) return "N/A";

        // Correct Weighted Average Formula: (WeightedSum / TotalPercentage) * 100
        // Example: Grade 5.0 (20%). totalScore = 1. totalPercentage = 20.
        // (1 / 20) * 100 = 5.0
        const average = (totalScore / totalPercentage) * 100;
        return average.toFixed(2);
    };

    const findNextExam = () => {
        const today = new Date().toISOString().split('T')[0];
        const upcomingExams = exams
            .filter(e => e.startDate >= today && e.status === 'Programado')
            .sort((a, b) => new Date(a.startDate).getTime() - new Date(b.startDate).getTime());
        return upcomingExams.length > 0 ? `${upcomingExams[0].title} (${upcomingExams[0].startDate})` : "Ninguno";
    };

    const todaySchedules = schedules
        .filter(s => s.dayOfWeek === new Date().getDay())
        .sort((a, b) => a.startTime.localeCompare(b.startTime));

    const recentGrades = grades
        .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime())
        .slice(0, 3);

    const getTeacherName = (teacherId: string) => teachers.find(t => t.id === teacherId)?.name || 'N/A';

    return (
        <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                <StatCard icon={<AcademicCapIcon />} title="Promedio General" value={calculateOverallAverage()} color="#3B82F6" />
                <StatCard icon={<ExamsIcon />} title="Próximo Examen" value={findNextExam()} color="#10B981" />
                <StatCard icon={<ClipboardDocumentListIcon />} title="Clases Hoy" value={String(todaySchedules.length)} color="#F97316" />
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                <Card className="lg:col-span-2">
                    <h3 className="font-bold text-lg mb-4">Horario de Hoy</h3>
                    {todaySchedules.length > 0 ? (
                        <div className="space-y-3">
                            {todaySchedules.map(s => (
                                <div key={s.id} className="flex justify-between items-center p-3 bg-gray-50 rounded-lg dark:bg-gray-700/50">
                                    <div>
                                        <p className="font-semibold text-primary dark:text-accent">{s.startTime} - {s.endTime}</p>
                                        <p className="font-bold text-text-primary dark:text-white">{s.subject}</p>
                                    </div>
                                    <p className="text-sm text-text-secondary dark:text-gray-400">{getTeacherName(s.teacherId)}</p>
                                </div>
                            ))}
                        </div>
                    ) : (
                        <p className="text-center py-4 text-text-secondary">No hay clases programadas para hoy.</p>
                    )}
                </Card>
                 <Card>
                    <h3 className="font-bold text-lg mb-4">Calificaciones Recientes</h3>
                    {recentGrades.length > 0 ? (
                        <ul className="space-y-3">
                           {recentGrades.map(grade => (
                               <li key={grade.id} className="flex justify-between items-center pb-2 border-b last:border-0 dark:border-gray-700">
                                   <div>
                                       <p className="font-semibold text-text-primary dark:text-white">{grade.subject}</p>
                                       <p className="text-xs text-text-secondary dark:text-gray-400">{grade.assignmentTitle}</p>
                                   </div>
                                   <span className="font-bold text-lg text-primary">{grade.score.toFixed(1)}</span>
                               </li>
                           ))}
                        </ul>
                    ) : (
                         <p className="text-center py-4 text-text-secondary">No hay calificaciones recientes.</p>
                    )}
                </Card>
            </div>
        </div>
    );
};

