const StudentManagementPage: React.FC = () => {
    const { students, campuses, addStudent, updateStudent, deleteStudent } = useData();
    const { user, sendPasswordReset } = useAuth();

    // ... (State definitions kept same)
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [isBulkOpen, setIsBulkOpen] = useState(false);
    const [editingStudent, setEditingStudent] = useState<Student | null>(null);
    const [viewingStudent, setViewingStudent] = useState<Student | null>(null);
    const [deletingStudent, setDeletingStudent] = useState<Student | null>(null);
    const [resettingPasswordStudent, setResettingPasswordStudent] = useState<Student | null>(null);

    const [searchQuery, setSearchQuery] = useState('');
    const [notification, setNotification] = useState<{message: string, type: 'success' | 'error' | 'info'} | null>(null);

    const showNotification = (message: string, type: 'success' | 'error' | 'info') => {
        setNotification({ message, type });
        setTimeout(() => setNotification(null), 5000);
    };

    const filteredStudents = students
        .filter(s => {
            const matchesSearch = s.name.toLowerCase().includes(searchQuery.toLowerCase()) || s.documentNumber.includes(searchQuery);
            if (user?.role === UserRole.SUPER_ADMIN) return matchesSearch;
            return matchesSearch && s.campusId === user?.campusId;
        });

    const handleSaveStudent = async (studentData: Omit<Student, 'id' | 'rollNumber' | 'role' | 'avatar'>) => {
        try {
            if (editingStudent) {
                await updateStudent(editingStudent.id, studentData);
                showNotification('Estudiante actualizado.', 'success');
            } else {
                await addStudent(studentData);
                showNotification('Estudiante creado.', 'success');
            }
            setIsModalOpen(false);
            setEditingStudent(null);
        } catch (error: any) {
            showNotification(`Error: ${error.message}`, 'error');
        }
    };

    const handleDeleteStudent = async () => {
        if (!deletingStudent) return;
        try {
            await deleteStudent(deletingStudent.id);
            showNotification('Estudiante eliminado.', 'success');
        } catch (error: any) {
            showNotification(`Error: ${error.message}`, 'error');
        }
        setDeletingStudent(null);
    };

    const handleBulkSave = async (newStudents: ParsedStudent[], campusId: string) => {
        setIsBulkOpen(false);
        showNotification(`Procesando ${newStudents.length} estudiantes...`, 'info');
        const selectedCampus = campuses.find(c => c.id === campusId);

        let successCount = 0;
        let errorsCount = 0;

        for (const student of newStudents) {
            try {
                await addStudent({
                    ...student,
                    campusId: campusId,
                    campusName: selectedCampus?.name,
                    status: 'active'
                });
                successCount++;
                // Add a small delay to prevent rate limiting from backend auth services
                await new Promise(resolve => setTimeout(resolve, 300));
            } catch (error) {
                console.error(error);
                errorsCount++;
            }
        }

        if (errorsCount > 0) {
            showNotification(`Carga completada. ${successCount} éxitos, ${errorsCount} fallos.`, 'info');
        } else {
            showNotification(`¡${successCount} estudiantes cargados exitosamente!`, 'success');
        }
    };

    const handleSendResetLink = async () => {
        if (!resettingPasswordStudent) return;
        try {
            await sendPasswordReset(resettingPasswordStudent.email);
            showNotification(`Enlace enviado a ${resettingPasswordStudent.email}`, 'success');
        } catch (error: any) {
            showNotification(`Error: ${error.message}`, 'error');
        }
        setResettingPasswordStudent(null);
