                            value={searchQuery} 
                            onChange={e => setSearchQuery(e.target.value)}
                            className="w-full md:w-64 p-2 border rounded bg-gray-100 dark:bg-gray-700 dark:text-white dark:border-gray-600 focus:outline-none focus:ring-2 focus:ring-primary"
                        />
                        <button onClick={() => setIsBulkOpen(true)} className="bg-secondary text-primary-text font-bold py-2 px-4 rounded transition duration-300 flex items-center gap-2 whitespace-nowrap hover:bg-yellow-500 dark:text-gray-900 text-sm">
                            <UploadIcon className="w-5 h-5"/> Carga Masiva
                        </button>
                        <button onClick={() => { setEditingStudent(null); setIsModalOpen(true); }} className="bg-primary text-white font-bold py-2 px-4 rounded transition duration-300 flex items-center gap-2 whitespace-nowrap hover:bg-blue-700 text-sm">
                            <PlusIcon className="w-5 h-5"/> Añadir
                        </button>
                    </div>
                </div>

                <div className="overflow-x-auto">
                    <table className="w-full text-sm text-left text-gray-500 dark:text-gray-400">
                        <thead className="text-xs text-gray-700 uppercase bg-gray-50 dark:bg-gray-700 dark:text-gray-400">
                            <tr>
                                <th className="px-4 py-3">Nombre</th>
                                <th className="px-4 py-3">Documento</th>
                                <th className="px-4 py-3">Clase</th>
                                {user?.role === UserRole.SUPER_ADMIN && <th className="px-4 py-3">Sede</th>}
                                <th className="px-4 py-3">Estado</th>
                                <th className="px-4 py-3 text-right">Acciones</th>
                            </tr>
                        </thead>
                        <tbody>
                            {filteredStudents.length > 0 ? (
                                filteredStudents.map(student => (
                                    <tr key={student.id} className="bg-white border-b hover:bg-gray-50 dark:bg-gray-800 dark:border-gray-700 dark:hover:bg-gray-600">
                                        <td className="px-4 py-3 font-medium text-gray-900 whitespace-nowrap dark:text-white">{student.name}</td>
