```typescript
import React, { useState, useEffect } from 'react';
import { useAuth } from '../../context/AuthContext';
import { TeacherCourseAssignment } from '../../types';
import { useData } from '../../context/DataContext';
import { PlusIcon, TrashIcon, BookOpenIcon } from '../icons';

interface ClassLogEntry {
    id: string;
    classId: string;
    subject: string;
    className: string;
    date: string;
    note: string;
    faultsCount: number;
}

const ClassLogWidget: React.FC = () => {
    const { user } = useAuth();
    const { assignments } = useData();
    const [myClasses, setMyClasses] = useState<TeacherCourseAssignment[]>([]);
    const [selectedClassId, setSelectedClassId] = useState<string>('');
    const [note, setNote] = useState('');
    const [faults, setFaults] = useState<number>(0);
    const [logs, setLogs] = useState<ClassLogEntry[]>([]);

    useEffect(() => {
        if (user) {
            const teacherAssignments = assignments.filter(a => a.teacherId === user.id);
            setMyClasses(teacherAssignments);
            if (teacherAssignments.length > 0) {
                setSelectedClassId(teacherAssignments[0].id);
            }

            // Load logs
            const savedLogs = localStorage.getItem(`teacher_logs_${user.id}`);
            if (savedLogs) {
                setLogs(JSON.parse(savedLogs));
            }
        }
    }, [user, assignments]);

    const handleSaveLog = (e: React.FormEvent) => {
        e.preventDefault();
        if (!selectedClassId || !note) return;

        const selectedClass = myClasses.find(c => c.id === selectedClassId);
        if (!selectedClass) return;

        const newLog: ClassLogEntry = {
            id: Date.now().toString(),
            classId: selectedClassId,
            subject: selectedClass.subject,
            className: `${selectedClass.class} - ${selectedClass.section}`,
            date: new Date().toLocaleDateString('es-ES'),
            note,
            faultsCount: faults
        };

        const updatedLogs = [newLog, ...logs];
        setLogs(updatedLogs);
        if (user) {
            localStorage.setItem(`teacher_logs_${user.id}`, JSON.stringify(updatedLogs));
        }

        setNote('');
        setFaults(0);
    };

    const handleDeleteLog = (id: string) => {
        const updatedLogs = logs.filter(l => l.id !== id);
        setLogs(updatedLogs);
        if (user) {
            localStorage.setItem(`teacher_logs_${user.id}`, JSON.stringify(updatedLogs));
        }
    };

    if (myClasses.length === 0) return null;

    const filteredLogs = logs.filter(l => l.classId === selectedClassId);

    return (
        <div className="bg-white dark:bg-slate-800 rounded-xl shadow-md border border-gray-100 dark:border-slate-700 overflow-hidden flex flex-col h-full">
            <div className="p-4 bg-gradient-to-r from-purple-600 to-indigo-600 text-white">
                <h3 className="font-bold text-lg flex items-center gap-2">
                    <BookOpenIcon className="w-5 h-5" />
                    Anotaciones de Clase
                </h3>
                <p className="text-xs text-purple-100 mt-1">Registra actividades y novedades.</p>
            </div>

            <div className="p-4 flex-grow flex flex-col gap-4">
                <form onSubmit={handleSaveLog} className="space-y-3">
                    <div>
                        <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Asignatura</label>
                        <select 
                            value={selectedClassId} 
                            onChange={(e) => setSelectedClassId(e.target.value)}
                            className="w-full p-2 text-sm border rounded bg-gray-50 dark:bg-slate-700 dark:border-slate-600 dark:text-white"
                        >
                            {myClasses.map(c => (
                                <option key={c.id} value={c.id}>{c.subject} ({c.class}-{c.section})</option>
                            ))}
                        </select>
                    </div>

                    <div>
                        <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Nota / Actividad</label>
                        <textarea 
                            value={note}
                            onChange={(e) => setNote(e.target.value)}
                            placeholder="Ej: Tema visto, incidente, tarea..."
                            className="w-full p-2 text-sm border rounded bg-gray-50 dark:bg-slate-700 dark:border-slate-600 dark:text-white resize-none"
                            rows={2}
                            required
                        />
                    </div>

                    <div className="flex items-end gap-3">
                        <div className="flex-1">
                            <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Total Faltas (Hoy)</label>
                            <input 
                                type="number" 
                                min="0"
                                value={faults}
                                onChange={(e) => setFaults(parseInt(e.target.value) || 0)}
                                className="w-full p-2 text-sm border rounded bg-gray-50 dark:bg-slate-700 dark:border-slate-600 dark:text-white"
                            />
                        </div>
                        <button 
                            type="submit" 
                            className="bg-purple-600 text-white p-2 rounded hover:bg-purple-700 transition-colors h-[38px] flex items-center gap-1 text-sm font-bold px-4"
                        >
                            <PlusIcon className="w-4 h-4" /> Guardar
                        </button>
                    </div>
                </form>

                <div className="border-t dark:border-gray-700 pt-3 flex-grow overflow-hidden flex flex-col">
                    <h4 className="text-xs font-bold text-gray-500 uppercase mb-2">Historial Reciente</h4>
                    <div className="overflow-y-auto flex-grow space-y-2 pr-1 custom-scrollbar max-h-[200px]">
                        {filteredLogs.length > 0 ? (
                            filteredLogs.map(log => (
                                <div key={log.id} className="p-3 bg-gray-50 dark:bg-slate-700/50 rounded-lg text-sm group relative">
                                    <div className="flex justify-between items-start">
                                        <span className="font-bold text-gray-700 dark:text-gray-200">{log.date}</span>
                                        {log.faultsCount > 0 && (
                                            <span className="text-xs bg-red-100 text-red-700 px-2 py-0.5 rounded-full font-bold">
                                                {log.faultsCount} Faltas
                                            </span>
                                        )}
                                    </div>
                                    <p className="text-gray-600 dark:text-gray-300 mt-1 pr-6">{log.note}</p>
                                    <button 
                                        onClick={() => handleDeleteLog(log.id)}
                                        className="absolute top-2 right-2 text-gray-400 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity"
                                    >
                                        <TrashIcon className="w-4 h-4" />
                                    </button>
                                </div>
                            ))
                        ) : (
                            <p className="text-center text-gray-400 text-xs py-4">No hay anotaciones para esta clase.</p>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

export default ClassLogWidget;
