const CampusAdminDashboard: React.FC = () => {
    const { user } = useAuth();
    const { students, teachers, exams } = useData();
    const [stats, setStats] = useState({ students: 0, staff: 0, attendance: 0, upcomingExams: 0 });

    useEffect(() => {
        if (!user?.campusId) return;

        const allAttendance: AttendanceRecord[] = JSON.parse(localStorage.getItem('school_attendance') || '[]');

        const today = new Date().toISOString().split('T')[0];
        const campusUpcomingExams = exams.filter(e => e.campusId === user.campusId && e.status === 'Programado' && e.startDate >= today);

        const campusStudents = students.filter(s => s.campusId === user.campusId);
        const campusTeachers = teachers.filter(t => t.campusId === user.campusId);

        const studentIdsOnCampus = new Set(campusStudents.map(s => s.id));
        const todayAttendanceRecords = allAttendance.filter(r => r.date === today && studentIdsOnCampus.has(r.studentId));
        const presentCount = todayAttendanceRecords.filter(r => r.status === 'Presente').length;

        const attendancePercentage = campusStudents.length > 0 ? Math.round((presentCount / campusStudents.length) * 100) : 0;

        setStats({
            students: campusStudents.length,
            staff: campusTeachers.length,
            attendance: attendancePercentage,
            upcomingExams: campusUpcomingExams.length
        });

    }, [user, students, teachers, exams]);

    return (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
            <StatCard icon={<StudentsIcon />} title={`Estudiantes (${user?.campusName})`} value={stats.students.toLocaleString('es-ES')} color="#3B82F6" />
            <StatCard icon={<StaffIcon />} title={`Personal (${user?.campusName})`} value={String(stats.staff)} color="#10B981" />
            <StatCard icon={<ExamsIcon />} title="Exámenes Programados" value={String(stats.upcomingExams)} color="#F97316" />
            <StatCard icon={<ExamsIcon />} title="Asistencia Hoy" value={`${stats.attendance}%`} color="#8B5CF6" trendColor={stats.attendance >= 90 ? 'green' : 'red'} />
