    );
};

const TeacherDashboard: React.FC = () => {
    const { user } = useAuth();
    const { schedules, communications, exams, teachers } = useData();

    const [mySchedules, setMySchedules] = useState<any[]>([]);
    const [currentClassId, setCurrentClassId] = useState<string | null>(null);
    const [latestAnnouncement, setLatestAnnouncement] = useState<Communication | null>(null);
    const [myExams, setMyExams] = useState<Exam[]>([]);
    const [teacher, setTeacher] = useState<Teacher | null>(null);

    useEffect(() => {
        if (user) {
            const currentTeacher = teachers.find(t => t.id === user.id);
            setTeacher(currentTeacher || null);

            const teacherSchedules = schedules.filter(s => s.teacherId === user.id);
            setMySchedules(teacherSchedules);

            const latest = communications
                .filter(c => !c.campusId || c.campusId === user.campusId)
                .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime())[0];
            setLatestAnnouncement(latest || null);

            if (currentTeacher) {
                const teacherExams = exams.filter(ex => 
                    ex.campusId === currentTeacher.campusId &&
                    (ex.teacherId === currentTeacher.id || !ex.teacherId)
                );
                setMyExams(teacherExams);
            }
        }
    }, [user, teachers, schedules, communications, exams]); 

    useEffect(() => {
        const checkCurrentClass = () => {
            const now = new Date();
            const dayOfWeek = now.getDay();
            const currentTime = `${String(now.getHours()).padStart(2, '0')}:${String(now.getMinutes()).padStart(2, '0')}`;
            const activeClass = mySchedules.find(schedule => 
                schedule.dayOfWeek === dayOfWeek &&
                currentTime >= schedule.startTime &&
                currentTime < schedule.endTime
            );
            setCurrentClassId(activeClass ? activeClass.id : null);
        };
        checkCurrentClass();
        const intervalId = setInterval(checkCurrentClass, 60000);
        return () => clearInterval(intervalId);
    }, [mySchedules]);

    const findNextClass = () => {
        const now = new Date();
        const dayOfWeek = now.getDay();
        const currentTime = `${String(now.getHours()).padStart(2, '0')}:${String(now.getMinutes()).padStart(2, '0')}`;
        const upcomingToday = mySchedules.filter(s => s.dayOfWeek === dayOfWeek && s.startTime > currentTime).sort((a, b) => a.startTime.localeCompare(b.startTime));
        if (upcomingToday.length > 0) return { classInfo: upcomingToday[0], day: 'Hoy' };
        for (let i = 1; i <= 7; i++) {
            const nextDayIndex = (dayOfWeek + i) % 7;
            const upcomingNextDay = mySchedules.filter(s => s.dayOfWeek === nextDayIndex).sort((a, b) => a.startTime.localeCompare(b.startTime));
            if (upcomingNextDay.length > 0) {
                const nextDate = new Date();
                nextDate.setDate(now.getDate() + i);
                return { classInfo: upcomingNextDay[0], day: nextDate.toLocaleDateString('es-ES', { weekday: 'long' }) };
            }
        }
        return null;
    };

    // Calculate the start of the current week (assuming Monday is the first day)
    const today = new Date();
    const dayOfWeek = today.getDay(); // 0 (Sun) - 6 (Sat)
    const diff = today.getDate() - dayOfWeek + (dayOfWeek === 0 ? -6 : 1); // Get Monday of the current week
    const startOfWeek = new Date(today);
    startOfWeek.setDate(diff); // Set to this week's Monday

    const weekDates = [];
    // Generate only 6 days (Mon-Sat)
    for (let i = 0; i < 6; i++) {
        const dayDate = new Date(startOfWeek);
        dayDate.setDate(startOfWeek.getDate() + i);
        weekDates.push(dayDate);
    }

    // Dynamic month title
    const startMonth = weekDates[0].toLocaleString('es-ES', { month: 'long' }).replace(/^\w/, c => c.toUpperCase());
    const endMonth = weekDates[weekDates.length - 1].toLocaleString('es-ES', { month: 'long' }).replace(/^\w/, c => c.toUpperCase());
    const monthTitle = startMonth === endMonth ? startMonth : `${startMonth} - ${endMonth}`;

    const nextClass = findNextClass();

    return (
        <div className="space-y-4">
            <Card>
                <h3 className="font-semibold text-base mb-3">Resumen del Horario Semanal - {monthTitle}</h3>
                <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-6 gap-2">
                    {weekDates.map(dayDate => {
                        const dayOfWeekIndex = dayDate.getDay();
                        const dateString = dayDate.toISOString().split('T')[0];

                        const daySchedules = mySchedules
                            .filter(s => s.dayOfWeek === dayOfWeekIndex)
                            .map(s => ({ ...s, type: 'class', time: s.startTime }));

                        const dayExams = myExams
                            .filter(e => e.startDate === dateString && e.status === 'Programado')
                            .map(e => ({ ...e, type: 'exam', time: '00:00' }));

                        const dayEvents = [...daySchedules, ...dayExams].sort((a:any, b:any) => a.time.localeCompare(b.time));

                        return (
                            <div key={dateString} className="p-2 rounded-lg h-48 flex flex-col bg-gray-50 dark:bg-slate-700/50">
                                <p className="font-bold text-center border-b pb-1 mb-1 dark:border-slate-600 text-sm">
                                    {dayDate.getDate()} <span className="hidden md:inline">{dayDate.toLocaleDateString('es-ES', { weekday: 'short' })}</span>
                                </p>
                                <div className="space-y-1 overflow-y-auto flex-grow pr-1">
                                    {dayEvents.length > 0 ? dayEvents.map((event: any) => {
                                        if (event.type === 'class') {
                                            const schedule = event;
                                            const isCurrent = schedule.id === currentClassId;
                                            return (
                                                <div key={schedule.id} className={`p-1.5 rounded-md text-xs transition-all duration-300 ${isCurrent ? 'bg-green-100 dark:bg-green-900/50 border-l-4 border-green-500 shadow-md scale-105' : 'bg-surface dark:bg-slate-800'}`}>
                                                    <p className="font-semibold">{schedule.startTime} - {schedule.endTime}</p>
                                                    <p className="text-text-secondary dark:text-slate-300">{schedule.subject}</p>
                                                    <p className="text-text-secondary dark:text-slate-400">{schedule.class} - '{schedule.section}'</p>
                                                    {isCurrent && <span className="text-green-600 dark:text-green-400 font-bold animate-pulse text-[10px] uppercase">En Curso</span>}
                                                </div>
                                            );
                                        } else {
                                            const exam = event;
                                            return (
                                                    <div key={exam.id} className="p-1.5 rounded-md text-xs bg-purple-100 text-purple-800 dark:bg-purple-900/50 dark:text-purple-200">
                                                    <p className="font-semibold">Examen</p>
                                                    <p className="text-purple-700 dark:text-purple-200 font-bold">{exam.title}</p>
                                                    <p className="text-purple-600 dark:text-purple-300">Finaliza: {exam.endDate}</p>
                                                </div>
                                            );
                                        }
                                    }) : <p className="text-xs text-center text-gray-400 dark:text-slate-500 pt-4">Libre</p>}
                                </div>
                            </div>
                        );
                    })}
                </div>
            </Card>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="md:col-span-1 space-y-4">
                    <Card>
                        <h3 className="font-semibold text-base">Próxima Clase</h3>
                        {nextClass ? (
                            <>
                                <p className="text-sm text-text-secondary dark:text-slate-400">{nextClass.classInfo.subject} - {nextClass.classInfo.class} '{nextClass.classInfo.section}'</p>
                                <p className="text-primary font-semibold text-sm">{nextClass.day}, {nextClass.classInfo.startTime}</p>
                            </>
                        ) : <p className="text-sm text-text-secondary dark:text-slate-400">No hay más clases programadas.</p>}
                    </Card>
                    <Card>
                        <h3 className="font-semibold text-base">Clases Semanales</h3>
                        <p className="text-primary font-semibold text-2xl mt-1">{mySchedules.length}</p>
                        <p className="text-sm text-text-secondary dark:text-slate-400">Total de clases en su horario recurrente.</p>
                    </Card>
                    <Card>
                        <h3 className="font-semibold text-base">Anuncios Recientes</h3>
                        {latestAnnouncement ? (
                            <p className="text-sm text-text-secondary dark:text-slate-400 truncate">{latestAnnouncement.title}</p>
                        ) : (
                            <p className="text-sm text-text-secondary dark:text-slate-400">No hay anuncios nuevos.</p>
                        )}
                    </Card>
                </div>
                {/* Integration of ClassLogWidget in the dashboard grid */}
                <div className="md:col-span-2">
                    <ClassLogWidget />
                </div>
            </div>
        </div>
    );
};

