                                const daysRemaining = calculateDaysRemaining(event.date);
                                let remainingText;
                                if (daysRemaining === 0) {
                                    remainingText = 'Hoy';
                                } else if (daysRemaining === 1) {
                                    remainingText = 'Mañana';
                                } else {
                                    remainingText = `${daysRemaining} días restantes`;
                                }

                                return (
                                    <li key={event.id} className="flex justify-between items-center py-2 border-b last:border-b-0 dark:border-slate-700">
                                        <div>
                                            <p className="font-semibold">{event.title}</p>
                                            <p className="text-xs text-text-secondary dark:text-slate-400">
                                                {event.campusId ? (user?.role === UserRole.SUPER_ADMIN ? (JSON.parse(localStorage.getItem('school_campuses') || '[]')).find((c: Campus) => c.id === event.campusId)?.name : user?.campusName) : 'Todas las sedes'}
                                            </p>
                                        </div>
                                        <span className={`text-xs font-medium ${daysRemaining <= 7 ? 'text-red-500' : 'text-primary'}`}>
                                            {remainingText}
                                        </span>
                                    </li>
                                );
                            })}
