        const upcomingToday = mySchedules.filter(s => s.dayOfWeek === dayOfWeek && s.startTime > currentTime).sort((a, b) => a.startTime.localeCompare(b.startTime));
        if (upcomingToday.length > 0) return { classInfo: upcomingToday[0], day: 'Hoy' };
        for (let i = 1; i <= 7; i++) {
