        const encodedUri = encodeURI(csvContent);
        const link = document.createElement("a");
        link.setAttribute("href", encodedUri);
        link.setAttribute("download", "plantilla_anotaciones.csv");
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const selectedFile = e.target.files?.[0];
        if (selectedFile) {
            setFile(selectedFile);
            processFile(selectedFile);
        }
    };

    const processFile = (fileToProcess: File) => {
        setParsedData([]);
        setErrors([]);
        const reader = new FileReader();

        reader.onload = (e) => {
            const text = e.target?.result as string;
            const rows = text.split('\n').map(row => row.trim()).filter(row => row);
            const header = rows[0]?.split(',').map(h => h.trim().toLowerCase());

            const requiredHeaders = ["documento", "nota", "faltas"];
            if (!header || !requiredHeaders.every(h => header.includes(h))) {
                setErrors([{ rowIndex: 0, message: `El encabezado es inválido. Debe contener: ${requiredHeaders.join(', ')}` }]);
                return;
            }

            const validRows: any[] = [];
            const newErrors: { rowIndex: number, message: string }[] = [];
            const studentMap = new Map(students.map(s => [s.documentNumber, s]));

            for (let i = 1; i < rows.length; i++) {
                const values = rows[i].split(',');
                const rowData: any = {};
                header.forEach((h, index) => { rowData[h] = values[index]?.trim(); });

                const student = studentMap.get(rowData.documento);
                if (!student) {
                    newErrors.push({ rowIndex: i, message: `Estudiante con documento ${rowData.documento} no encontrado.` });
                    continue;
                }

                let score = null;
                if (rowData.nota && rowData.nota !== '') {
                    score = parseFloat(rowData.nota);
                    if (isNaN(score) || score < 0.1 || score > 5.0) {
                        newErrors.push({ rowIndex: i, message: `Nota '${rowData.nota}' inválida.` });
                        continue;
                    }
                }

                let faults = 0;
                if (rowData.faltas && rowData.faltas !== '') {
                    faults = parseInt(rowData.faltas);
                    if (isNaN(faults) || faults < 0) {
                        newErrors.push({ rowIndex: i, message: `Faltas '${rowData.faltas}' inválido.` });
                        continue;
                    }
                }

                if (score === null && faults === 0 && !rowData.concepto) continue;

                validRows.push({
                    student,
                    score,
                    faults,
                    observation: rowData.concepto || ''
                });
            }
            setParsedData(validRows);
            setErrors(newErrors);
        };
        reader.readAsText(fileToProcess);
    };

    return (
        <div className="fixed inset-0 bg-black bg-opacity-60 z-[60] flex justify-center items-center p-4">
            <Card className="w-full max-w-2xl flex flex-col max-h-[90vh]">
