                        <h4 className="font-bold text-blue-800 dark:text-blue-300 mb-2 text-sm">1. Descargar Plantilla</h4>
                        <p className="text-xs text-blue-600 dark:text-blue-400 mb-3">Obtén el archivo CSV con los estudiantes de esta clase.</p>
                        <button onClick={handleDownloadTemplate} className="bg-white text-blue-600 border border-blue-200 font-bold py-1.5 px-3 rounded text-xs flex items-center gap-2 hover:bg-blue-50 transition-colors w-full justify-center">
                            <DownloadIcon className="w-4 h-4"/> Descargar
                        </button>
                    </div>
                    <div className="bg-gray-50 dark:bg-gray-700/30 p-3 rounded-lg border border-gray-200 dark:border-gray-600">
                        <h4 className="font-bold text-gray-800 dark:text-gray-300 mb-2 text-sm">2. Subir Archivo</h4>
                        <p className="text-xs text-gray-600 dark:text-gray-400 mb-2">Sube el archivo diligenciado.</p>
                        <input type="file" accept=".csv" onChange={handleFileChange} className="w-full text-xs text-gray-500 file:mr-2 file:py-1.5 file:px-3 file:rounded-full file:border-0 file:text-xs file:font-semibold file:bg-primary/10 file:text-primary hover:file:bg-primary/20 cursor-pointer" />
                    </div>
                </div>

                <div className="flex-grow overflow-y-auto border rounded-lg bg-gray-50 dark:bg-gray-800 dark:border-gray-700 p-2 mb-4 min-h-[150px]">
                    {errors.length > 0 ? (
                        <div className="text-red-600 text-sm">
                            <p className="font-bold mb-1">Errores encontrados ({errors.length}):</p>
                            <ul className="list-disc list-inside text-xs">
                                {errors.slice(0, 5).map((err, i) => <li key={i}>Fila {err.rowIndex + 1}: {err.message}</li>)}
                                {errors.length > 5 && <li>...y {errors.length - 5} más</li>}
                            </ul>
                        </div>
                    ) : parsedData.length > 0 ? (
                        <div className="text-green-600 text-sm">
                            <p className="font-bold">¡Archivo válido!</p>
                            <p>Se procesarán {parsedData.length} registros.</p>
                            <ul className="list-disc list-inside text-xs mt-2 text-gray-600 dark:text-gray-400">
                                {parsedData.slice(0, 3).map((row, i) => (
                                    <li key={i}>{row.student.name}: Nota {row.score || '-'}, Faltas {row.faults}</li>
                                ))}
                                {parsedData.length > 3 && <li>...</li>}
                            </ul>
                        </div>
                    ) : (
                        <p className="text-gray-400 text-center text-sm pt-10">Sube un archivo para previsualizar.</p>
                    )}
                </div>

                <div className="flex justify-end gap-3 border-t pt-3 dark:border-gray-700">
                    <button onClick={onClose} className="px-4 py-2 bg-gray-200 text-gray-800 rounded font-bold hover:bg-gray-300 text-sm dark:bg-gray-700 dark:text-white">Cancelar</button>
                    <button 
                        onClick={() => onSave(parsedData)} 
                        disabled={parsedData.length === 0 || errors.length > 0 || isProcessing}
                        className="px-4 py-2 bg-primary text-white rounded font-bold hover:bg-blue-700 text-sm disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
                    >
                        {isProcessing ? 'Procesando...' : 'Confirmar Carga'}
                    </button>
                </div>
            </Card>
        </div>
    );
};

const ClassAnnotationsPage: React.FC = () => {
    const { user } = useAuth();
    const { assignments, students: allStudents, attendanceRecords, saveAttendance, addGrade, grades } = useData();

    const [myClasses, setMyClasses] = useState<TeacherCourseAssignment[]>([]);
    const [selectedClassId, setSelectedClassId] = useState<string>('');
    const [selectedPeriod, setSelectedPeriod] = useState<number>(1);
    const [numberOfPeriods, setNumberOfPeriods] = useState(4);
    const [concepts, setConcepts] = useState<{ code: string; text: string }[]>([]);

    const [inputs, setInputs] = useState<Record<string, StudentInput>>({});
    const [savedStatus, setSavedStatus] = useState<Record<string, boolean>>({});
    const [activityLogs, setActivityLogs] = useState<ActivityLog[]>([]);
    const [isBulkModalOpen, setIsBulkModalOpen] = useState(false);
    const [isBulkProcessing, setIsBulkProcessing] = useState(false);
    const [expandedStudentId, setExpandedStudentId] = useState<string | null>(null);

    useEffect(() => {
        let settings = null;
        const globalSettingsRaw = localStorage.getItem('school_global_settings');
        if (globalSettingsRaw) settings = JSON.parse(globalSettingsRaw);

        if (user?.campusId) {
            const campusSettingsRaw = localStorage.getItem(`school_settings_${user.campusId}`);
            if (campusSettingsRaw) settings = { ...settings, ...JSON.parse(campusSettingsRaw) };
        }
        if (settings && settings.numberOfPeriods) setNumberOfPeriods(settings.numberOfPeriods);

        const today = new Date().toISOString().split('T')[0];
        const currentPeriod = getPeriodFromDate(today, settings?.numberOfPeriods || 4);
        setSelectedPeriod(currentPeriod);

        if (user) {
            const teacherAssignments = assignments.filter(a => a.teacherId === user.id);
            setMyClasses(teacherAssignments);
            if (teacherAssignments.length > 0) {
                setSelectedClassId(teacherAssignments[0].id);
            }
            const savedLogs = localStorage.getItem(`teacher_activity_logs_${user.id}`);
            if (savedLogs) {
                setActivityLogs(JSON.parse(savedLogs));
            }
        }

        const parsedConcepts = conceptsCSV
            .split('\n').slice(1).filter(row => row.trim())
            .map(row => {
                const parts = row.split(';');
                const code = parts.pop()?.trim() || '';
                const text = parts.join(';').trim().replace(/^\uFEFF/, '');
                return { code, text };
            }).filter(c => c.code && c.text);
        setConcepts(parsedConcepts);

    }, [user, assignments]);

    const selectedClass = myClasses.find(c => c.id === selectedClassId);

    const classStudents = useMemo(() => {
        if (!selectedClass) return [];
        return allStudents.filter(s => 
            s.class === selectedClass.class && 
            s.section === selectedClass.section &&
            s.status === 'active'
        ).sort((a, b) => a.name.localeCompare(b.name));
    }, [selectedClass, allStudents]);

    const getSavedAccumulatedFaults = (studentId: string) => {
        return attendanceRecords
            .filter(r => 
                r.studentId === studentId && 
                r.period === selectedPeriod && 
                (r.status === 'Ausente' || r.status === 'Justificado')
            )
            .reduce((acc, curr) => acc + (curr.count || 1), 0);
    };

    const getStudentHistory = (studentId: string) => {
        if (!selectedClass) return [];

        // Grades for this period & subject
        const relevantGrades = grades.filter(g => 
            g.studentId === studentId && 
            g.subject === selectedClass.subject &&
            getPeriodFromDate(g.date, numberOfPeriods) === selectedPeriod
        ).map(g => ({
            id: g.id,
            date: g.date,
            type: 'Nota',
            value: g.score.toString(),
            detail: g.comments || '-'
        }));

        // Attendance for this period
        const relevantAttendance = attendanceRecords.filter(r => 
            r.studentId === studentId && 
            r.period === selectedPeriod &&
            (r.status === 'Ausente' || r.status === 'Justificado')
        ).map(r => ({
            id: r.id,
            date: r.date,
            type: 'Falta',
            value: r.count?.toString() || '1',
            detail: r.status
        }));

        return [...relevantGrades, ...relevantAttendance].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    };

    const handleInputChange = (studentId: string, field: keyof StudentInput, value: string) => {
        setInputs(prev => ({
            ...prev,
            [studentId]: {
                ...prev[studentId],
                [field]: value
            }
        }));
        if (savedStatus[studentId]) {
            setSavedStatus(prev => ({ ...prev, [studentId]: false }));
        }
    };

    const validateScore = (scoreStr: string): boolean => {
        if (!scoreStr) return true;
        const score = parseFloat(scoreStr);
        return !isNaN(score) && score >= 0.1 && score <= 5.0;
    };

    const addToLog = (studentName: string, actions: string[], observation?: string) => {
        const newLog: ActivityLog = {
            id: Date.now().toString() + Math.random().toString(),
            studentName,
            actionType: actions.length > 1 ? 'mixed' : (actions[0]?.includes('Nota') ? 'grade' : 'attendance'),
            details: actions.join(' | '),
            timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
            observation
        };

        const updatedLogs = [newLog, ...activityLogs].slice(0, 100);
        setActivityLogs(updatedLogs);
        if (user) {
            localStorage.setItem(`teacher_activity_logs_${user.id}`, JSON.stringify(updatedLogs));
        }
    };

    const clearLogs = () => {
        setActivityLogs([]);
        if (user) localStorage.removeItem(`teacher_activity_logs_${user.id}`);
    };

    const handleSaveStudentRow = async (student: Student) => {
        const input = inputs[student.id] || { score: '', faults: '', observation: '' };
        const score = parseFloat(input.score);
        const newFaults = parseInt(input.faults);
        const today = new Date().toISOString().split('T')[0];

        if (!validateScore(input.score)) {
            alert("La calificación debe estar entre 0.1 y 5.0");
            return;
        }
        if (!input.score && !input.faults && !input.observation) return;

        const logActions: string[] = [];

        try {
            if (!isNaN(score) && selectedClass) {
                const selectedConcept = concepts.find(c => c.text === input.observation);
                await addGrade({
                    studentId: student.id,
                    subject: selectedClass.subject,
                    class: student.class,
                    assignmentTitle: `Nota de Clase - ${new Date().toLocaleDateString()}`,
                    score: score,
                    percentage: 10,
                    date: today,
                    comments: input.observation || 'Nota rápida desde bitácora',
                    conceptCode: selectedConcept ? selectedConcept.code : '' 
                });
                logActions.push(`Nota: ${score}`);
            }

            if (!isNaN(newFaults) && newFaults > 0) {
                const existingRecord = attendanceRecords.find(r => 
                    r.studentId === student.id && 
                    r.date === today &&
                    r.period === selectedPeriod
                );

                const totalDailyFaults = (existingRecord?.count || 0) + newFaults;

                await saveAttendance({
                    studentId: student.id,
                    date: today,
                    status: 'Ausente',
                    count: totalDailyFaults,
                    period: selectedPeriod
                });
                logActions.push(`Faltas: +${newFaults}`);
            } else if (input.observation && logActions.length === 0) {
                 logActions.push(`Observación registrada`);
            }

            if (logActions.length > 0) {
                addToLog(student.name, logActions, input.observation);
            }

            setSavedStatus(prev => ({ ...prev, [student.id]: true }));
            setInputs(prev => ({
                ...prev,
                [student.id]: { score: '', faults: '', observation: '' }
            }));

            setTimeout(() => {
                setSavedStatus(prev => ({ ...prev, [student.id]: false }));
            }, 2000);

        } catch (error) {
            console.error("Error al guardar anotación:", error);
            alert("Error al guardar los datos.");
        }
    };

    const handleBulkSave = async (parsedData: any[]) => {
        if (!selectedClass) return;
        setIsBulkProcessing(true);
        const today = new Date().toISOString().split('T')[0];
        let processedCount = 0;

        try {
            for (const row of parsedData) {
                const { student, score, faults, observation } = row;
                let processed = false;

                // 1. Guardar Nota
                if (score !== null) {
                    const selectedConcept = concepts.find(c => c.text === observation);
                    await addGrade({
                        studentId: student.id,
                        subject: selectedClass.subject,
                        class: student.class,
                        assignmentTitle: `Nota de Clase (Masiva) - ${new Date().toLocaleDateString()}`,
                        score: score,
                        percentage: 10,
                        date: today,
                        comments: observation || 'Nota masiva',
                        conceptCode: selectedConcept ? selectedConcept.code : ''
                    });
                    processed = true;
                }

                // 2. Guardar Faltas
                if (faults > 0) {
                    const existingRecord = attendanceRecords.find(r => 
                        r.studentId === student.id && 
                        r.date === today &&
                        r.period === selectedPeriod
                    );
                    const totalDailyFaults = (existingRecord?.count || 0) + faults;
                    await saveAttendance({
                        studentId: student.id,
                        date: today,
                        status: 'Ausente',
                        count: totalDailyFaults,
                        period: selectedPeriod
                    });
                    processed = true;
                } else if (observation && !processed) {
                    // Si solo hay observación y no se guardó nota, no tenemos dónde guardarla actualmente sin nota/falta
                    // Podríamos crear una nota con valor 0 o similar, pero por ahora lo omitimos si no es nota/falta.
                }

                if (processed) processedCount++;
                // Small delay to prevent rate limits
                await new Promise(resolve => setTimeout(resolve, 50));
            }

            if (processedCount > 0) {
                addToLog("Carga Masiva", [`Procesados ${processedCount} estudiantes`], "Actualización vía archivo");
            }
            setIsBulkModalOpen(false);
        } catch (error) {
            console.error("Error en carga masiva:", error);
            alert("Ocurrió un error durante la carga masiva.");
        } finally {
            setIsBulkProcessing(false);
        }
    };

    if (myClasses.length === 0) return (
        <Card>
            <div className="p-10 text-center">
                <p className="text-gray-500 dark:text-gray-400 text-lg">No tienes asignaturas asignadas para gestionar.</p>
            </div>
        </Card>
    );

    return (
        <div className="space-y-6">
            <Card className="flex flex-col h-full border-none shadow-none bg-transparent p-0">
                <div className="bg-white dark:bg-slate-800 rounded-xl shadow-md border border-gray-100 dark:border-slate-700 overflow-hidden flex flex-col">

                    {/* Header Section */}
                    <div className="p-6 bg-gradient-to-r from-blue-700 to-cyan-600 text-white flex flex-col md:flex-row justify-between items-center gap-4">
                        <div>
                            <h2 className="font-bold text-2xl flex items-center gap-3">
                                <SaveIcon className="w-8 h-8" />
                                Bitácora de Clase
                            </h2>
                            <p className="text-sm text-blue-100 mt-1 opacity-90">Gestión rápida de notas y asistencia diaria.</p>
                        </div>

                        <div className="flex flex-col sm:flex-row gap-4 w-full md:w-auto bg-white/10 p-2 rounded-lg backdrop-blur-sm items-end">
                            <div className="flex-1 w-full">
                                <label className="block text-xs font-bold text-white uppercase mb-1 opacity-80">Asignatura</label>
                                <select 
                                    value={selectedClassId} 
                                    onChange={(e) => setSelectedClassId(e.target.value)}
                                    className="w-full md:w-56 p-2 text-sm border-none rounded bg-white text-gray-800 focus:ring-2 focus:ring-blue-300 outline-none shadow-sm"
                                >
                                    {myClasses.map(c => (
                                        <option key={c.id} value={c.id}>{c.subject} ({c.class}-{c.section})</option>
                                    ))}
                                </select>
                            </div>
                            <div className="flex-1 w-full">
                                <label className="block text-xs font-bold text-white uppercase mb-1 opacity-80">Periodo</label>
                                <select 
                                    value={selectedPeriod} 
                                    onChange={(e) => setSelectedPeriod(Number(e.target.value))}
                                    className="w-full md:w-32 p-2 text-sm border-none rounded bg-white text-gray-800 focus:ring-2 focus:ring-blue-300 outline-none shadow-sm"
                                >
                                    {Array.from({ length: numberOfPeriods }, (_, i) => i + 1).map(p => (
                                        <option key={p} value={p}>Periodo {p}</option>
                                    ))}
                                </select>
                            </div>
                            <button 
                                onClick={() => setIsBulkModalOpen(true)}
                                className="bg-white text-blue-700 font-bold py-2 px-4 rounded shadow-sm hover:bg-blue-50 transition-colors text-sm flex items-center gap-2 whitespace-nowrap h-[36px]"
                            >
                                <UploadIcon className="w-4 h-4" /> Carga Masiva
                            </button>
                        </div>
                    </div>

                    {/* Main Table */}
                    <div className="overflow-x-auto">
                        <table className="w-full text-sm text-left">
                            <thead className="text-xs text-gray-700 uppercase bg-gray-50 dark:bg-slate-900 dark:text-gray-300">
                                <tr>
                                    <th className="px-6 py-4">Estudiante</th>
                                    <th className="px-4 py-4 w-32 text-center">Nota</th>
                                    <th className="px-4 py-4">Concepto</th>
                                    <th className="px-4 py-4 w-24 text-center">Faltas</th>
                                    <th className="px-4 py-4 text-center w-32" title="Total faltas en este periodo">Total Faltas</th>
                                    <th className="px-4 py-4 text-center w-24">Acción</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-200 dark:divide-slate-700">
                                {classStudents.map(student => {
                                    const input = inputs[student.id] || { score: '', faults: '', observation: '' };
                                    const isSaved = savedStatus[student.id];
                                    const baseAccumulated = getSavedAccumulatedFaults(student.id);
                                    const pendingFaults = parseInt(input.faults) || 0;
                                    const isScoreValid = validateScore(input.score);
                                    const isExpanded = expandedStudentId === student.id;

                                    return (
                                        <React.Fragment key={student.id}>
                                            <tr className={`bg-white dark:bg-slate-800 hover:bg-blue-50 dark:hover:bg-slate-700/50 transition-colors ${isExpanded ? 'bg-blue-50 dark:bg-slate-700/50' : ''}`}>
                                                {/* 1. Estudiante */}
                                                <td className="px-6 py-3 font-medium text-gray-900 dark:text-white whitespace-nowrap">
                                                    <div className="flex items-center gap-2">
                                                        <button 
                                                            onClick={() => setExpandedStudentId(isExpanded ? null : student.id)}
                                                            className="text-gray-400 hover:text-blue-600 transition-colors focus:outline-none"
                                                        >
                                                            {isExpanded ? <ChevronDownIcon className="w-4 h-4" /> : <ChevronRightIcon className="w-4 h-4" />}
                                                        </button>
                                                        {student.name}
                                                    </div>
                                                </td>

                                                {/* 2. Nota */}
                                                <td className="px-4 py-3 relative">
                                                    <input 
                                                        type="number" 
                                                        min="0.1" max="5.0" step="0.1"
                                                        value={input.score}
                                                        onChange={(e) => handleInputChange(student.id, 'score', e.target.value)}
                                                        placeholder="-"
                                                        className={`w-full p-2 text-center border rounded-lg text-sm outline-none transition-all dark:bg-slate-700 dark:text-white 
                                                            ${!isScoreValid 
                                                                ? 'border-red-500 ring-2 ring-red-100 bg-red-50 dark:bg-red-900/20' 
                                                                : 'border-gray-300 focus:border-blue-500 focus:ring-2 focus:ring-blue-100 dark:border-slate-600'}`}
                                                    />
                                                    {!isScoreValid && (
                                                        <div className="absolute top-full left-0 w-full text-[10px] text-red-600 text-center font-bold bg-white dark:bg-slate-800 z-10 shadow-lg border border-red-200 rounded mt-1 p-1">
                                                            Mín 0.1 - Máx 5.0
                                                        </div>
                                                    )}
                                                </td>

                                                {/* 3. Concepto */}
                                                <td className="px-4 py-3">
                                                    <select 
                                                        value={input.observation}
                                                        onChange={(e) => handleInputChange(student.id, 'observation', e.target.value)}
                                                        className="w-full p-2 border border-gray-300 rounded-lg text-xs focus:border-blue-500 focus:ring-2 focus:ring-blue-100 outline-none transition-all dark:bg-slate-700 dark:border-slate-600 dark:text-white truncate"
                                                    >
                                                        <option value="">Seleccione concepto...</option>
                                                        {concepts.map(c => (
                                                            <option key={c.code} value={c.text} title={c.text}>
                                                                {c.text.length > 60 ? c.text.substring(0, 60) + '...' : c.text}
                                                            </option>
                                                        ))}
                                                    </select>
                                                </td>

                                                {/* 4. Faltas (Input) */}
                                                <td className="px-4 py-3">
                                                    <input 
                                                        type="number" 
                                                        min="0"
                                                        value={input.faults}
                                                        onChange={(e) => handleInputChange(student.id, 'faults', e.target.value)}
                                                        placeholder="0"
                                                        className="w-full p-2 text-center border border-gray-300 rounded-lg text-sm focus:border-red-500 focus:ring-2 focus:ring-red-100 outline-none transition-all dark:bg-slate-700 dark:border-slate-600 dark:text-white"
                                                    />
                                                </td>

                                                {/* 5. Total Faltas (Accumulated) */}
                                                <td className="px-4 py-3 text-center">
                                                    <div className="flex items-center justify-center gap-2">
                                                        <span className={`text-sm font-bold px-3 py-1 rounded-full border ${baseAccumulated > 0 ? 'bg-red-50 text-red-700 border-red-200 dark:bg-red-900/20 dark:text-red-300 dark:border-red-800' : 'bg-gray-50 text-gray-600 border-gray-200 dark:bg-gray-700 dark:text-gray-400 dark:border-gray-600'}`}>
                                                            {baseAccumulated}
                                                        </span>
                                                        {pendingFaults > 0 && (
                                                            <span className="text-xs font-bold text-blue-600 dark:text-blue-400 animate-pulse bg-blue-50 dark:bg-blue-900/30 px-2 py-0.5 rounded-full">
                                                                + {pendingFaults} = {baseAccumulated + pendingFaults}
                                                            </span>
                                                        )}
                                                    </div>
                                                </td>

                                                {/* 6. Acción */}
                                                <td className="px-4 py-3 text-center">
                                                    <button 
                                                        onClick={() => handleSaveStudentRow(student)}
                                                        disabled={(!input.score && !input.faults && !input.observation) || isSaved || !isScoreValid}
                                                        className={`p-2 rounded-full transition-all duration-300 shadow-sm ${
                                                            isSaved 
                                                                ? 'bg-green-100 text-green-600 hover:bg-green-200 dark:bg-green-900/30 dark:text-green-400' 
                                                                : (input.score || input.faults || input.observation) && isScoreValid
                                                                    ? 'bg-blue-600 text-white hover:bg-blue-700 hover:shadow-md transform hover:scale-105' 
                                                                    : 'bg-gray-100 text-gray-300 dark:bg-gray-700 dark:text-gray-600 cursor-not-allowed'
                                                        }`}
                                                        title="Guardar cambios"
                                                    >
                                                        {isSaved ? <CheckIcon className="w-5 h-5" /> : <SaveIcon className="w-5 h-5" />}
                                                    </button>
                                                </td>
                                            </tr>

                                            {/* Detailed History Expansion */}
                                            {isExpanded && (
                                                <tr className="bg-gray-50 dark:bg-slate-900/50">
                                                    <td colSpan={6} className="p-4">
                                                        <div className="bg-white dark:bg-slate-800 rounded-lg border border-gray-200 dark:border-slate-700 p-4 shadow-inner">
                                                            <h4 className="font-bold text-sm text-gray-700 dark:text-gray-300 mb-3 flex items-center gap-2">
                                                                <ClipboardCheckIcon className="w-4 h-4 text-blue-500"/>
                                                                Historial del Periodo {selectedPeriod}
                                                            </h4>
                                                            <div className="overflow-x-auto">
                                                                <table className="w-full text-xs text-left">
                                                                    <thead className="bg-gray-100 dark:bg-slate-700 text-gray-600 dark:text-gray-400">
                                                                        <tr>
                                                                            <th className="px-3 py-2">Fecha</th>
                                                                            <th className="px-3 py-2">Tipo</th>
                                                                            <th className="px-3 py-2">Valor</th>
                                                                            <th className="px-3 py-2">Detalle</th>
                                                                        </tr>
                                                                    </thead>
                                                                    <tbody className="divide-y divide-gray-100 dark:divide-slate-700">
                                                                        {getStudentHistory(student.id).map((h, idx) => (
                                                                            <tr key={`${h.id}-${idx}`}>
                                                                                <td className="px-3 py-2">{new Date(h.date).toLocaleDateString()}</td>
                                                                                <td className="px-3 py-2">
